// Try multiple ways to get markdown content
let markdown = '';

// Method 1: From input directly
if ($input.item.json?.message?.content) {
  markdown = $input.item.json.message.content;
}
// Method 2: From json.content directly
else if ($input.item.json?.content) {
  markdown = $input.item.json.content;
}
// Method 3: From Markdown Version node
else if ($('Markdown Version')?.item?.json?.message?.content) {
  markdown = $('Markdown Version').item.json.message.content;
}
// Method 4: Check text field
else if ($input.item.json?.text) {
  markdown = $input.item.json.text;
}

// If still no markdown found, throw error
if (!markdown || typeof markdown !== 'string') {
  throw new Error('No markdown content found. Check connection from Markdown Version node.');
}

// Get title for filename
let title = 'blog-post';
try {
  if ($('Title')?.item?.json?.message?.content) {
    title = $('Title').item.json.message.content;
  }
} catch (e) {
  // Use default title if Title node not available yet
  title = 'markdown-file-' + Date.now();
}

// Clean filename (remove special chars)
const fileName = title
  .replace(/[^a-z0-9\s-]/gi, '')
  .replace(/\s+/g, '-')
  .toLowerCase()
  .substring(0, 100) + '.md';

// Convert text to binary buffer
const buffer = Buffer.from(markdown, 'utf-8');

// Return binary data in format n8n expects
return {
  json: {
    fileName: fileName,
    contentLength: markdown.length
  },
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'text/markdown',
      fileName: fileName,
      fileExtension: 'md'
    }
  }
};
